                .build();
        this.chatClient = chatClientBuilder
                .defaultAdvisors(ragAdvisor)
                .build();
    }

    @PostMapping("/ask")
    public Answer ask(@RequestBody Question question) {
        String someRequestTimeMetadataValue = ...;
        return chatClient.prompt()
